  1→//! Data structures for the cross-function interesting input pool.
  2→//!
  3→//! Values discovered during exploration of one function are pooled and reused
  4→//! as seeds for other functions with matching parameter types. Entry identity
  5→//! is the `(ty, value)` pair — behaviors accumulate across functions.
  6→
  7→use std::collections::{HashMap, HashSet};
  8→
  9→use serde::{Deserialize, Serialize};
 10→
 11→use crate::boundary_dict;
 12→use crate::execution_record::ErrorInfo;
 13→use crate::explorer;
 14→use crate::protocol::ExecuteResult;
 15→use crate::types::{ParamInfo, TypeInfo};
 16→
 17→/// How severe the behavior triggered by an input was.
 18→///
 19→/// Ordered low-to-high so that [`Ord`] gives natural severity comparison.
 20→#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord, Hash, Serialize, Deserialize)]
 21→#[serde(rename_all = "snake_case")]
 22→pub enum Severity {
 23→    /// Novel path exercised by very few inputs, no error.
 24→    RarePath = 1,
 25→    /// Thrown error with an application-defined exception type.
 26→    HandledError = 2,
 27→    /// Thrown error with a runtime error type (TypeError, panic, etc.).
 28→    UnhandledError = 3,
 29→    /// Frontend process died, timed out, or protocol error.
 30→    Crash = 4,
 31→}
 32→
 33→/// A single behavior observed when running a particular input against a function.
 34→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
 35→pub struct BehaviorObservation {
 36→    /// Fully qualified function identifier.
 37→    pub function: String,
 38→    /// Branch point that was exercised.
 39→    pub branch_id: u32,
 40→    /// Severity of the observed behavior.
 41→    pub severity: Severity,
 42→}
 43→
 44→/// Grouping key for deduplication and eviction decisions.
 45→///
 46→/// Two observations with the same `BehaviorSig` are considered redundant
 47→/// witnesses to the same behavior.
 48→#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]
 49→pub struct BehaviorSig {
 50→    /// Fully qualified function identifier.
 51→    pub function_id: String,
 52→    /// Branch point that was exercised.
 53→    pub branch_id: u32,
 54→    /// Severity of the observed behavior.
 55→    pub severity: Severity,
 56→}
 57→
 58→impl From<&BehaviorObservation> for BehaviorSig {
 59→    fn from(obs: &BehaviorObservation) -> Self {
 60→        Self {
 61→            function_id: obs.function.clone(),
 62→            branch_id: obs.branch_id,
 63→            severity: obs.severity,
 64→        }
 65→    }
 66→}
 67→
 68→/// A single entry in the interesting input pool.
 69→///
 70→/// Identity is the `(ty, value)` pair. When the same value is observed to
 71→/// trigger interesting behavior in a different function, its `behaviors`
 72→/// vector grows rather than creating a duplicate entry.
 73→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
 74→pub struct PoolEntry {
 75→    /// The concrete input value (JSON-encoded).
 76→    pub value: serde_json::Value,
 77→    /// Type of the value, used for matching against function parameters.
 78→    #[serde(rename = "type")]
 79→    pub ty: TypeInfo,
 80→    /// All interesting behaviors this value has triggered across functions.
 81→    pub behaviors: Vec<BehaviorObservation>,
 82→    /// Epoch at which this entry was first added to the pool.
 83→    pub discovered_epoch: u64,
 84→    /// Most recent epoch at which this entry triggered a new behavior.
 85→    pub last_hit_epoch: u64,
 86→}
 87→
 88→/// Known runtime error type names per language. An error whose `error_type`
 89→/// matches any of these (case-insensitive) is classified as `UnhandledError`
 90→/// rather than `HandledError`.
 91→const RUNTIME_ERROR_TYPES: &[&str] = &[
 92→    // JavaScript / TypeScript
 93→    "typeerror",
 94→    "referenceerror",
 95→    "rangeerror",
 96→    "syntaxerror",
 97→    "urierror",
 98→    "evalerror",
 99→    // Go
100→    "runtime_error",
101→    "panic",
102→    // Java / JVM
103→    "nullpointerexception",
104→    "classcastexception",
105→    "arrayindexoutofboundsexception",
106→    "stackoverflowerror",
107→    // Rust
108→    "panic",
109→    // Python
110→    "attributeerror",
111→    "indexerror",
112→    "keyerror",
113→    "zerodivisionerror",
114→];
115→
116→/// Classify the severity of an execution result.
117→///
118→/// - `Crash` if the frontend itself failed (indicated by `is_crash`).
119→/// - `UnhandledError` if thrown_error matches a known runtime error type.
120→/// - `HandledError` if thrown_error is present but not a known runtime type.
121→/// - `RarePath` if no error occurred and the path is novel.
122→pub fn classify_severity(thrown_error: Option<&ErrorInfo>, is_crash: bool) -> Severity {
123→    if is_crash {
124→        return Severity::Crash;
125→    }
126→    match thrown_error {
127→        Some(err) => {
128→            let lower = err.error_type.to_lowercase();
129→            if RUNTIME_ERROR_TYPES.contains(&lower.as_str()) {
130→                Severity::UnhandledError
131→            } else {
132→                Severity::HandledError
133→            }
134→        }
135→        None => Severity::RarePath,
136→    }
137→}
138→
139→/// Default maximum entries per type bucket.
140→pub const DEFAULT_BUCKET_CAP: usize = 50;
141→
142→/// Coverage tier for eviction decisions.
143→///
144→/// Tier 1 entries are sole witnesses to at least one behavior; tier 0 entries
145→/// have all behaviors covered by other witnesses.
146→#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord)]
147→pub enum CoverageTier {
148→    /// All behaviors have other witnesses — safe to evict first.
149→    Redundant = 0,
150→    /// Sole witness to at least one behavior — evict only as last resort.
151→    UniqueWitness = 1,
152→}
153→
154→/// Serialize a `TypeInfo` into the canonical string key used for bucket lookup.
155→///
156→/// `TypeInfo` contains `serde_json::Value` (in `Complex.metadata`) which does
157→/// not implement `Hash`, so we use a deterministic JSON serialization as the
158→/// map key instead.
159→fn type_key(ty: &TypeInfo) -> String {
160→    serde_json::to_string(ty).unwrap_or_else(|_| format!("{ty:?}"))
161→}
162→
163→/// The interesting input pool: type-keyed buckets of inputs that triggered
164→/// interesting behaviors during exploration.
165→#[derive(Debug, Clone, Serialize, Deserialize)]
166→pub struct InterestingPool {
167→    /// Pool format version.
168→    pub version: u32,
169→    /// Monotonic counter incremented each scan.
170→    pub epoch: u64,
171→    /// Type-keyed buckets of interesting inputs. Keys are canonical JSON
172→    /// serializations of [`TypeInfo`] (see [`type_key`]).
173→    pub buckets: HashMap<String, Vec<PoolEntry>>,
174→    /// Maximum entries per type bucket.
175→    #[serde(default = "default_bucket_cap")]
176→    pub bucket_cap: usize,
177→}
178→
179→fn default_bucket_cap() -> usize {
180→    DEFAULT_BUCKET_CAP
181→}
182→
183→impl Default for InterestingPool {
184→    fn default() -> Self {
185→        Self {
186→            version: 2,
187→            epoch: 0,
188→            buckets: HashMap::new(),
189→            bucket_cap: DEFAULT_BUCKET_CAP,
190→        }
191→    }
192→}
193→
194→impl InterestingPool {
195→    /// Compute the coverage tier for an entry within its bucket.
196→    ///
197→    /// An entry is `UniqueWitness` if at least one of its behaviors has no
198→    /// other witness in the same bucket.
199→    fn coverage_tier(
200→        entry_idx: usize,
201→        bucket: &[PoolEntry],
202→        sig_witnesses: &HashMap<BehaviorSig, Vec<usize>>,
203→    ) -> CoverageTier {
204→        for obs in &bucket[entry_idx].behaviors {
205→            let sig = BehaviorSig::from(obs);
206→            if let Some(witnesses) = sig_witnesses.get(&sig)
207→                && witnesses.len() == 1
208→                && witnesses[0] == entry_idx
209→            {
210→                return CoverageTier::UniqueWitness;
211→            }
212→        }
213→        CoverageTier::Redundant
214→    }
215→
216→    /// Build the behavior→witness index for a bucket.
217→    fn build_sig_index(bucket: &[PoolEntry]) -> HashMap<BehaviorSig, Vec<usize>> {
218→        let mut index: HashMap<BehaviorSig, Vec<usize>> = HashMap::new();
219→        for (i, entry) in bucket.iter().enumerate() {
220→            for obs in &entry.behaviors {
221→                index.entry(BehaviorSig::from(obs)).or_default().push(i);
222→            }
223→        }
224→        index
225→    }
226→
227→    /// Quality score for eviction ordering (higher = better, keep longer).
228→    ///
229→    /// `severity × breadth` where breadth = log2(1 + distinct_function_count).
230→    fn quality_score(entry: &PoolEntry) -> f64 {
231→        let max_severity = entry
232→            .behaviors
233→            .iter()
234→            .map(|b| b.severity as u32)
235→            .max()
236→            .unwrap_or(0);
237→        let distinct_fns: std::collections::HashSet<&str> =
238→            entry.behaviors.iter().map(|b| b.function.as_str()).collect();
239→        let breadth = (1.0 + distinct_fns.len() as f64).log2();
240→        max_severity as f64 * breadth
241→    }
242→
243→    /// Return all pool values matching the given type.
244→    ///
245→    /// Used to inject cross-function seeds: values that triggered interesting
246→    /// behavior in other functions with compatible parameter types.
247→    pub fn values_for_type(&self, ty: &TypeInfo) -> Vec<serde_json::Value> {
248→        let key = type_key(ty);
249→        self.buckets
250→            .get(&key)
251→            .map(|entries| entries.iter().map(|e| e.value.clone()).collect())
252→            .unwrap_or_default()
253→    }
254→
255→    /// Insert an entry into the pool, evicting if the bucket is at capacity.
256→    ///
257→    /// Returns `true` if the entry was inserted (or merged), `false` if
258→    /// it was rejected because all existing entries have higher priority.
259→    pub fn insert(&mut self, entry: PoolEntry) -> bool {
260→        let key = type_key(&entry.ty);
261→        let bucket = self.buckets.entry(key).or_default();
262→
263→        // Check if this value already exists in the bucket
264→        if let Some(existing) = bucket.iter_mut().find(|e| e.value == entry.value) {
265→            // Merge behaviors
266→            for obs in entry.behaviors {
267→                let sig = BehaviorSig::from(&obs);
268→                let already = existing
269→                    .behaviors
270→                    .iter()
271→                    .any(|b| BehaviorSig::from(b) == sig);
272→                if !already {
273→                    existing.behaviors.push(obs);
274→                }
275→            }
276→            existing.last_hit_epoch = existing.last_hit_epoch.max(entry.last_hit_epoch);
277→            return true;
278→        }
279→
280→        // If bucket has room, just insert
281→        if bucket.len() < self.bucket_cap {
282→            bucket.push(entry);
283→            return true;
284→        }
285→
286→        // Eviction: find the lowest-priority entry to replace
287→        let sig_index = Self::build_sig_index(bucket);
288→        let mut worst_idx = None;
289→        let mut worst_tier = CoverageTier::UniqueWitness;
290→        let mut worst_quality = f64::INFINITY;
291→
292→        for i in 0..bucket.len() {
293→            let tier = Self::coverage_tier(i, bucket, &sig_index);
294→            let quality = Self::quality_score(&bucket[i]);
295→            if (tier, quality as u64) < (worst_tier, worst_quality as u64) {
296→                worst_idx = Some(i);
297→                worst_tier = tier;
298→                worst_quality = quality;
299→            }
300→        }
301→
302→        // Only evict if the new entry has higher quality than the worst
303→        let new_quality = Self::quality_score(&entry);
304→        if let Some(idx) = worst_idx
305→            && (worst_tier == CoverageTier::Redundant || new_quality > worst_quality)
306→        {
307→            bucket[idx] = entry;
308→            return true;
309→        }
310→
311→        false
312→    }
313→}
314→
315→/// Load the interesting pool from a JSON file at the given path.
316→///
317→/// Acquires an exclusive flock to prevent concurrent reads during a write.
318→/// Returns `Ok(None)` if the file does not exist (without acquiring a lock).
319→pub fn load_pool(path: &std::path::Path) -> Result<Option<InterestingPool>, std::io::Error> {
320→    if !path.exists() {
321→        return Ok(None);
322→    }
323→    let _lock = crate::file_lock::FileLock::acquire(path)?;
324→    load_pool_unlocked(path)
325→}
326→
327→/// Load without acquiring a lock (for use when caller already holds the lock).
328→fn load_pool_unlocked(path: &std::path::Path) -> Result<Option<InterestingPool>, std::io::Error> {
329→    match std::fs::read_to_string(path) {
330→        Ok(content) => {
331→            let pool: InterestingPool = serde_json::from_str(&content)
332→                .map_err(|e| std::io::Error::new(std::io::ErrorKind::InvalidData, e))?;
333→            Ok(Some(pool))
334→        }
335→        Err(e) if e.kind() == std::io::ErrorKind::NotFound => Ok(None),
336→        Err(e) => Err(e),
337→    }
338→}
339→
340→/// Save the interesting pool to a JSON file at the given path.
341→///
342→/// Acquires an exclusive flock, then uses atomic write (temp file + rename).
343→/// Creates parent directories on first write. Keys are sorted for deterministic output.
344→pub fn save_pool(pool: &InterestingPool, path: &std::path::Path) -> Result<(), std::io::Error> {
345→    let _lock = crate::file_lock::FileLock::acquire(path)?;
346→    save_pool_unlocked(pool, path)
347→}
348→
349→/// Best-effort save: skips if another process holds the lock.
350→pub fn save_pool_best_effort(pool: &InterestingPool, path: &std::path::Path) -> Result<bool, std::io::Error> {
351→    match crate::file_lock::FileLock::try_acquire(path)? {
352→        Some(_lock) => {
353→            save_pool_unlocked(pool, path)?;
354→            Ok(true)
355→        }
356→        None => Ok(false),
357→    }
358→}
359→
360→fn save_pool_unlocked(pool: &InterestingPool, path: &std::path::Path) -> Result<(), std::io::Error> {
361→    if let Some(parent) = path.parent() {
362→        std::fs::create_dir_all(parent)?;
363→    }
364→
365→    // Sort buckets by type key for deterministic output
366→    let sorted: std::collections::BTreeMap<&String, &Vec<PoolEntry>> =
367→        pool.buckets.iter().collect();
368→
369→    let wrapper = serde_json::json!({
370→        "version": pool.version,
371→        "epoch": pool.epoch,
372→        "bucket_cap": pool.bucket_cap,
373→        "buckets": sorted,
374→    });
375→
376→    let content = serde_json::to_string_pretty(&wrapper)
377→        .map_err(std::io::Error::other)?;
378→
379→    // Atomic write: temp file + rename
380→    let tmp_path = path.with_extension("tmp");
381→    std::fs::write(&tmp_path, content)?;
382→    std::fs::rename(&tmp_path, path)?;
383→
384→    Ok(())
385→}
386→
387→/// Paths exercised by at most this many inputs qualify as rare during harvesting.
388→pub const DEFAULT_RARITY_THRESHOLD: u32 = 2;
389→
390→/// Harvest interesting inputs from raw exploration results into the pool.
391→///
392→/// Decomposes each execution's input vector into individual `(value, TypeInfo)`
393→/// pairs, filters out boundary-dict values (already tried everywhere), classifies
394→/// severity, and inserts into the pool. For error-triggering executions all inputs
395→/// are harvested; for non-error executions only those on rare paths (exercised by
396→/// ≤ `DEFAULT_RARITY_THRESHOLD` inputs) are kept.
397→///
398→/// Returns the number of pool entries inserted or merged.
399→pub fn harvest_from_exploration(
400→    pool: &mut InterestingPool,
401→    raw_results: &[(Vec<serde_json::Value>, ExecuteResult)],
402→    params: &[ParamInfo],
403→    function_name: &str,
404→) -> usize {
405→    if raw_results.is_empty() || params.is_empty() {
406→        return 0;
407→    }
408→
409→    // Build path frequency map for rarity classification.
410→    let mut path_counts: HashMap<u64, u32> = HashMap::new();
411→    let hashes: Vec<u64> = raw_results
412→        .iter()
413→        .map(|(_, result)| {
414→            let h = explorer::path_hash(result, &explorer::LoopBuckets::default());
415→            *path_counts.entry(h).or_default() += 1;
416→            h
417→        })
418→        .collect();
419→
420→    // Pre-compute boundary value sets per parameter position for filtering.
421→    let boundary_sets: Vec<HashSet<serde_json::Value>> = params
422→        .iter()
423→        .map(|p| {
424→            boundary_dict::get_boundary_values(&p.typ)
425→                .into_iter()
426→                .map(|entry| entry.value)
427→                .collect()
428→        })
429→        .collect();
430→
431→    let epoch = pool.epoch;
432→    let mut inserted = 0;
433→
434→    for (idx, (inputs, exec_result)) in raw_results.iter().enumerate() {
435→        let severity = classify_severity(exec_result.thrown_error.as_ref(), false);
436→
437→        // For RarePath, only harvest if the path is actually rare.
438→        if severity == Severity::RarePath {
439→            let count = path_counts.get(&hashes[idx]).copied().unwrap_or(0);
440→            if count > DEFAULT_RARITY_THRESHOLD {
441→                continue;
442→            }
443→        }
444→
445→        // Determine branch_id from execution's branch path.
446→        let branch_id = exec_result
447→            .branch_path
448→            .last()
449→            .map(|d| d.branch_id)
450→            .unwrap_or(0);
451→
452→        let obs = BehaviorObservation {
453→            function: function_name.to_string(),
454→            branch_id,
455→            severity,
456→        };
457→
458→        // Decompose input vector into individual (value, type) entries.
459→        for (i, value) in inputs.iter().enumerate() {
460→            if i >= params.len() {
461→                break;
462→            }
463→
464→            // Skip boundary-dict values — they're tried everywhere already.
465→            if boundary_sets[i].contains(value) {
466→                continue;
467→            }
468→
469→            let entry = PoolEntry {
470→                value: value.clone(),
471→                ty: params[i].typ.clone(),
472→                behaviors: vec![obs.clone()],
473→                discovered_epoch: epoch,
474→                last_hit_epoch: epoch,
475→            };
476→
477→            if pool.insert(entry) {
478→                inserted += 1;
479→            }
480→        }
481→
482→        // For multi-param functions with compound types, also store the full
483→        // input vector so correlated multi-arg patterns are preserved.
484→        if params.len() > 1
485→            && inputs.iter().zip(params.iter()).any(|(_, p)| {
486→                matches!(p.typ, TypeInfo::Object { .. } | TypeInfo::Array { .. })
487→            })
488→        {
489→            let compound_type = TypeInfo::Array {
490→                element: Box::new(TypeInfo::Unknown),
491→            };
492→            let compound_entry = PoolEntry {
493→                value: serde_json::Value::Array(inputs.clone()),
494→                ty: compound_type,
495→                behaviors: vec![obs],
496→                discovered_epoch: epoch,
497→                last_hit_epoch: epoch,
498→            };
499→            if pool.insert(compound_entry) {
500→                inserted += 1;
501→            }
502→        }
503→    }
504→
505→    inserted
506→}
