508→#[cfg(test)]
509→mod tests {
510→    use super::*;
511→
512→    #[test]
513→    fn severity_ordering() {
514→        assert!(Severity::RarePath < Severity::HandledError);
515→        assert!(Severity::HandledError < Severity::UnhandledError);
516→        assert!(Severity::UnhandledError < Severity::Crash);
517→    }
518→
519→    #[test]
520→    fn behavior_sig_from_observation() {
521→        let obs = BehaviorObservation {
522→            function: "myModule.foo".into(),
523→            branch_id: 3,
524→            severity: Severity::UnhandledError,
525→        };
526→        let sig = BehaviorSig::from(&obs);
527→        assert_eq!(sig.function_id, "myModule.foo");
528→        assert_eq!(sig.branch_id, 3);
529→        assert_eq!(sig.severity, Severity::UnhandledError);
530→    }
531→
532→    #[test]
533→    fn pool_entry_serde_round_trip() {
534→        let entry = PoolEntry {
535→            value: serde_json::json!(42),
536→            ty: TypeInfo::Int,
537→            behaviors: vec![BehaviorObservation {
538→                function: "mod.bar".into(),
539→                branch_id: 1,
540→                severity: Severity::Crash,
541→            }],
542→            discovered_epoch: 0,
543→            last_hit_epoch: 1,
544→        };
545→        let json = serde_json::to_string(&entry).expect("serialize");
546→        let back: PoolEntry = serde_json::from_str(&json).expect("deserialize");
547→        assert_eq!(entry, back);
548→    }
549→
550→    #[test]
551→    fn behavior_sig_hash_equality() {
552→        use std::collections::HashSet;
553→        let sig1 = BehaviorSig {
554→            function_id: "f".into(),
555→            branch_id: 1,
556→            severity: Severity::RarePath,
557→        };
558→        let sig2 = sig1.clone();
559→        let mut set = HashSet::new();
560→        set.insert(sig1);
561→        assert!(set.contains(&sig2));
562→    }
563→
564→    // -- classify_severity tests --
565→
566→    #[test]
567→    fn classify_crash_overrides_error() {
568→        let err = ErrorInfo {
569→            error_type: "TypeError".into(),
570→            message: "oops".into(),
571→            stack: None,
572→            error_category: None,
573→        };
574→        assert_eq!(classify_severity(Some(&err), true), Severity::Crash);
575→    }
576→
577→    #[test]
578→    fn classify_runtime_error_as_unhandled() {
579→        let err = ErrorInfo {
580→            error_type: "TypeError".into(),
581→            message: "cannot read property".into(),
582→            stack: None,
583→            error_category: None,
584→        };
585→        assert_eq!(classify_severity(Some(&err), false), Severity::UnhandledError);
586→    }
587→
588→    #[test]
589→    fn classify_custom_error_as_handled() {
590→        let err = ErrorInfo {
591→            error_type: "ValidationError".into(),
592→            message: "invalid input".into(),
593→            stack: None,
594→            error_category: None,
595→        };
596→        assert_eq!(classify_severity(Some(&err), false), Severity::HandledError);
597→    }
598→
599→    #[test]
600→    fn classify_no_error_as_rare_path() {
601→        assert_eq!(classify_severity(None, false), Severity::RarePath);
602→    }
603→
604→    #[test]
605→    fn classify_case_insensitive() {
606→        let err = ErrorInfo {
607→            error_type: "REFERENCEERROR".into(),
608→            message: "x is not defined".into(),
609→            stack: None,
610→            error_category: None,
611→        };
612→        assert_eq!(classify_severity(Some(&err), false), Severity::UnhandledError);
613→    }
614→
615→    // -- InterestingPool tests --
616→
617→    fn make_entry(value: serde_json::Value, function: &str, severity: Severity) -> PoolEntry {
618→        PoolEntry {
619→            value: value.clone(),
620→            ty: TypeInfo::Int,
621→            behaviors: vec![BehaviorObservation {
622→                function: function.into(),
623→                branch_id: 1,
624→                severity,
625→            }],
626→            discovered_epoch: 0,
627→            last_hit_epoch: 0,
628→        }
629→    }
630→
631→    #[test]
632→    fn pool_insert_and_merge() {
633→        let mut pool = InterestingPool::default();
634→        let e1 = make_entry(serde_json::json!(42), "foo", Severity::RarePath);
635→        assert!(pool.insert(e1));
636→
637→        // Same value, different behavior — should merge
638→        let e2 = PoolEntry {
